// Set date range: last 7 days
const today = new Date();
const since = new Date(today);
since.setDate(since.getDate() - 7);

const fmt = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    since: fmt(since),
    until: fmt(today),
    accounts: [
      { id: 'act_464237024205104', name: 'Flow States Retreats' },
      { id: 'act_1426936257455201', name: 'Emma Maidment Business' },
      { id: 'act_414785961683125', name: 'Flow OS' }
    ]
  }
}];

// Split accounts into individual items for parallel fetching
const { since, until, accounts } = $input.first().json;
return accounts.map(acc => ({
  json: { account_id: acc.id, account_name: acc.name, since, until }
}));

// Merge campaign list and insights data — preserve account identity
const allItems = $input.all();

const insights = [];
for (const item of allItems) {
  const data = item.json.data || [];
  const accountId = item.json.account_id || '';
  const accountName = item.json.account_name || '';
  for (const row of data) {
    insights.push({ ...row, account_id: accountId, account_name: accountName });
  }
}

if (insights.length === 0) {
  return [{ json: { accounts: [], total_adsets: 0 } }];
}

// Score each adset
const scored = insights.map(row => {
  const spend = parseFloat(row.spend || 0);
  const clicks = parseInt(row.clicks || 0);
  const impressions = parseInt(row.impressions || 0);
  const ctr = parseFloat(row.ctr || 0);
  const cpc = parseFloat(row.cpc || 0);
  const cpm = parseFloat(row.cpm || 0);
  const frequency = parseFloat(row.frequency || 0);

  const actions = row.actions || [];
  const leads = actions.find(a => a.action_type === 'lead' || a.action_type === 'offsite_conversion.fb_pixel_lead');
  const leadCount = leads ? parseInt(leads.value) : 0;
  const cpl = leadCount > 0 ? (spend / leadCount).toFixed(2) : null;

  let score = 5;
  if (ctr > 2) score += 2;
  else if (ctr > 1) score += 1;
  if (cpc < 1) score += 1;
  if (frequency > 4) score -= 2;
  if (frequency > 6) score -= 1;
  if (leadCount > 0) score += 2;
  score = Math.max(1, Math.min(10, score));

  return {
    account_id: row.account_id,
    account_name: row.account_name,
    campaign: row.campaign_name,
    adset: row.adset_name,
    spend: spend.toFixed(2),
    impressions,
    clicks,
    ctr: ctr.toFixed(2) + '%',
    cpc: cpc ? '$' + cpc.toFixed(2) : 'N/A',
    cpm: cpm ? '$' + cpm.toFixed(2) : 'N/A',
    frequency: frequency.toFixed(1),
    leads: leadCount,
    cpl: cpl ? '$' + cpl : 'N/A',
    performance_score: score,
    recommendation: score >= 7 ? 'SCALE' : score >= 5 ? 'MONITOR' : 'PAUSE OR REWORK'
  };
});

// Group by account
const accountMap = {};
for (const row of scored) {
  if (!accountMap[row.account_id]) {
    accountMap[row.account_id] = { account_name: row.account_name, adsets: [] };
  }
  accountMap[row.account_id].adsets.push(row);
}

// Sort each account's adsets by performance score
for (const acc of Object.values(accountMap)) {
  acc.adsets.sort((a, b) => b.performance_score - a.performance_score);
}

const accounts = Object.values(accountMap);
return [{ json: { accounts, total_adsets: scored.length } }];

// Format three separate Telegram messages — one per account
const { accounts } = $input.first().json;
const today = new Date().toLocaleDateString('en-AU', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const messages = [];

for (const acc of accounts) {
  const { account_name, adsets } = acc;

  const totalSpend = adsets.reduce((s, a) => s + parseFloat(a.spend), 0).toFixed(2);
  const totalLeads = adsets.reduce((s, a) => s + a.leads, 0);
  const avgCPL = totalLeads > 0 ? (parseFloat(totalSpend) / totalLeads).toFixed(2) : 'N/A';

  const top = adsets.slice(0, 3);
  const concerns = adsets.filter(a => a.performance_score < 5 || a.leads === 0);

  let msg = `📊 *${account_name} — Meta Ads Report*\n_${today}_\n\n`;
  msg += `💰 *Overview*\n`;
  msg += `• Spend: $${totalSpend}\n`;
  msg += `• Leads: ${totalLeads}\n`;
  msg += `• Avg CPL: ${totalLeads > 0 ? '$' + avgCPL : 'N/A'}\n`;
  msg += `• Active Ad Sets: ${adsets.length}\n\n`;

  msg += `🏆 *Top Performers*\n`;
  for (const [i, a] of top.entries()) {
    msg += `${i + 1}. ${a.adset}\n`;
    msg += `   CPL: ${a.cpl} | CTR: ${a.ctr} | Leads: ${a.leads} | Score: ${a.performance_score}/10\n`;
  }

  if (concerns.length > 0) {
    msg += `\n⚠️ *Needs Attention*\n`;
    for (const a of concerns.slice(0, 3)) {
      msg += `• ${a.adset} — ${a.recommendation} (Score: ${a.performance_score}/10, Leads: ${a.leads})\n`;
    }
  }

  msg += `\n_This message was sent automatically with n8n_`;

  // Telegram 4096 char limit
  const maxLen = 3800;
  messages.push({
    account_name,
    report_telegram: msg.length > maxLen ? msg.substring(0, maxLen) + '\n_[truncated]_' : msg
  });
}

// Return one item per account so downstream can send separately
return messages.map(m => ({ json: m }));

// Build Anthropic API request for optimisation analysis
const items = $input.all();
const insightsData = items.map(item => item.json);

const systemPrompt = `You are a Meta Ads performance analyst. Analyse the provided campaign data and deliver a concise, actionable optimisation report. Focus on: top performing campaigns, underperformers, budget recommendations, and 3-5 specific action items. Use clear headings and bullet points. Keep it under 3000 characters for Telegram delivery.`;

const userMessage = `Analyse this Meta Ads performance data and provide optimisation recommendations:\n\n${JSON.stringify(insightsData, null, 2)}`;

return [{
  json: {
    model: "claude-opus-4-5",
    max_tokens: 1500,
